import React, { useEffect } from 'react'
import { FontAwesomeIcon } from '@fortawesome/react-fontawesome'
import './Footer.css'
import {  faLinkedin, faGithub, faYoutube, faInstagram } from '@fortawesome/free-brands-svg-icons';


const Footer = () => {
  useEffect(() => {
    document.getElementById('footer_skill')?.addEventListener(
      'click',
      () => {
        document?.getElementById('portfolio.skills')?.scrollIntoView()
      },
      false
    )
    document.getElementById('footer_edu')?.addEventListener(
      'click',
      () => {
        document?.getElementById('portfolio.eduBackground')?.scrollIntoView()
      },
      false
    )
    document.getElementById('footer_exp')?.addEventListener(
      'click',
      () => {
        document?.getElementById('portfolio.experience')?.scrollIntoView()
      },
      false
    )
    document.getElementById('footer_linkedIn')?.addEventListener(
      'click',
      () => {
        window.open('https://www.linkedin.com/in/navnath-galande-60a726118/')
      },
      false
    )
    document.getElementById('footer_gitHub')?.addEventListener(
      'click',
      () => {
        window.open('https://github.com/navag')
      },
      false
    )
  }, [])
  return (
    <div className='row'>
      <div className='col-lg-4 col-md-4 col-sm-12 col-xs-12'>
        <h3>Reach me at</h3>
        Mob: +91 9403969285 <br />
        Email: navag99@gmail.com/navagforu@gmail.com
      </div>
      <div className='col-lg-4 col-md-4 col-sm-12 col-xs-12'>
      <h3>Quick Links</h3>
        <ul>
          <li className='link' id='footer_skill'>
            Skill's
          </li>
          <li className='link' id='footer_exp'>
            Experience
          </li>
          <li className='link' id='footer_edu'>
            Education
          </li>
          <li className='link' id='footer_blogs'>
            Blogs
          </li>
        </ul>
      </div>
      <div className='col-lg-4 col-md-4 col-sm-12 col-xs-12'>
      <h3>Explore more me at</h3>
      <div className='icons'>
        <FontAwesomeIcon id='footer_linkedIn' className='link' icon={faLinkedin} />
        <FontAwesomeIcon id='footer_gitHub' className='mL5 link' icon={faGithub} />
        <FontAwesomeIcon id='footer_youtube' className='mL5 link' icon={faYoutube} />
        <FontAwesomeIcon id='footer_inst' className='mL5 link' icon={faInstagram} />
      </div>
      </div>
    </div>
  )
}

export default Footer
