import React, { useEffect } from 'react'
import { Nav, Navbar } from 'react-bootstrap'
import './Navigation.css'
import ImageSection from '../ImageSection/ImageSection'
import Home from '../Home/Home'
import Skills from '../Skills/Skills'
import Experience from '../Experience/Experience'
import Education from '../Education/Education'
import Footer from '../Footer/Footer'

const Navigation = () => {
  useEffect(() => {
    document.getElementById('skills')?.addEventListener(
      'click',
      () => {
        document?.getElementById('portfolio.skills')?.scrollIntoView()
      },
      false
    )
    document.getElementById('Education')?.addEventListener(
      'click',
      () => {
        document?.getElementById('portfolio.eduBackground')?.scrollIntoView()
      },
      false
    )
    document.getElementById('Experience')?.addEventListener(
      'click',
      () => {
        document?.getElementById('portfolio.experience')?.scrollIntoView()
      },
      false
    )
  }, [])

  return (
    <div>
      <Navbar collapseOnSelect expand='lg' bg='dark' variant='dark'>
        <Navbar.Brand href='home'>NG</Navbar.Brand>
        <Navbar.Toggle aria-controls='responsive-navbar-nav' />
        <Navbar.Collapse id='responsive-navbar-nav'>
          <Nav className='mr-auto'>
            <Nav.Link id='skills'>Skill's</Nav.Link>
            <Nav.Link id='Experience'>Experience</Nav.Link>
            <Nav.Link id='Education'>Education</Nav.Link>
            <Nav.Link id='Blogs'>Blogs</Nav.Link>
          </Nav>
        </Navbar.Collapse>
      </Navbar>
      <div className='layout pd15'>
        <ImageSection />
        <Home />
        <Skills />
        <Experience />
        <Education />
      </div>
      <footer className='footer'>
        <Footer />
      </footer>
    </div>
  )
}

export default Navigation
