import React from 'react'
import './Home.css'
import { Button } from '@material-ui/core'

const Home = () => {
  const openGitHub = () => {
    window.open('https://github.com/navag')    
  }
  const downloadResume = () => {
    window.open('https://drive.google.com/file/d/1q3k9CmDY9HcwnxgB76LnmiKztXaFRKh4/view?usp=sharing')  
  }
  return (
    <div className='home'>
      Hey I am Navnath Galande, Have experience of developing cool web Applications. I have total 4 years of professional experience of working on Javascript
      stack. Along with Development I love to explore new Technologies and frameworks coming in market.
      <br />
      <div className='buttons'>
      <Button variant='outlined' color='secondary' onClick={downloadResume}>
        Doenload CV
      </Button>
      <span className='githubBtn'>
      <Button variant='outlined' color='secondary' onClick={openGitHub}>
        Git Hub
      </Button>
      </span>
      </div>
    </div>
  )
}

export default Home
